INSERT INTO content (concept, theory, code, example) VALUES
                                                         ('Arrays (Two Pointers)', 'Critical for optimizing O(n^2) search problems to O(n) in sorted arrays.', 'int l = 0, r = arr.length - 1; while(l < r) { int sum = arr[l] + arr[r]; if(sum == t) return true; else if(sum < t) l++; else r--; }', 'https://leetcode.com/problems/two-sum-ii-input-array-is-sorted/'),
                                                         ('Linked List (Fast & Slow Pointers)', 'Commonly used for cycle detection (Floyd''s) and finding the middle of a linked list.', 'ListNode slow = head, fast = head; while(fast != null && fast.next != null) { slow = slow.next; fast = fast.next.next; if(slow == fast) return true; }', 'https://leetcode.com/problems/linked-list-cycle/'),
                                                         ('Stack (Next Greater Element)', 'Maintain a monotonic decreasing stack to find the next strictly greater element in O(n) time.', 'Stack<Integer> st = new Stack<>(); for(int i=0; i<n; i++) { while(!st.isEmpty() && arr[st.peek()] < arr[i]) ans[st.pop()] = arr[i]; st.push(i); }', 'https://leetcode.com/problems/next-greater-element-i/'),
                                                         ('Queue (BFS - Level Order)', 'Standard for traversing trees level-by-level or finding the shortest path in an unweighted graph.', 'Queue<TreeNode> q = new LinkedList<>(); q.add(root); while(!q.isEmpty()){ int size = q.size(); for(int i=0; i<size; i++){ TreeNode curr = q.poll(); } }', 'https://leetcode.com/problems/binary-tree-level-order-traversal/'),
                                                         ('Binary Search (Search Space)', 'Used not just for arrays, but for finding a value in a monotonic search space (e.g., minimum capacity).', 'int l = min, r = max, ans = -1; while(l <= r) { int mid = l + (r - l) / 2; if(isValid(mid)) { ans = mid; r = mid - 1; } else l = mid + 1; }', 'https://leetcode.com/problems/split-array-largest-sum/'),
                                                         ('Sliding Window (Dynamic)', 'Used to find subarrays meeting a criteria by expanding the right pointer and shrinking the left.', 'int l = 0, sum = 0, minLen = MAX; for(int r = 0; r < n; r++) { sum += arr[r]; while(sum >= target) { minLen = Math.min(minLen, r - l + 1); sum -= arr[l++]; } }', 'https://leetcode.com/problems/minimum-size-subarray-sum/'),
                                                         ('Hash Map (Prefix Sum)', 'Crucial for finding subarrays that sum to K by storing the frequency of prefix sums.', 'Map<Integer, Integer> map = new HashMap<>(); map.put(0, 1); for(int num : nums) { sum += num; count += map.getOrDefault(sum - k, 0); map.put(sum, map.getOrDefault(sum, 0) + 1); }', 'https://leetcode.com/problems/subarray-sum-equals-k/'),
                                                         ('Backtracking (Permutations)', 'Essential for generating all possible combinations or permutations by exploring and undoing choices.', 'void backtrack(List<Integer> temp) { if(temp.size() == n) { res.add(new ArrayList<>(temp)); return; } for(int i=0; i<n; i++) { if(used[i]) continue; used[i]=true; temp.add(nums[i]); backtrack(temp); temp.remove(temp.size()-1); used[i]=false; } }', 'https://leetcode.com/problems/permutations/'),
                                                         ('Recursion (Memoization)', 'Storing results of expensive function calls to avoid redundant calculations in Top-Down DP.', 'int solve(int i) { if(i == 0) return 1; if(memo[i] != -1) return memo[i]; return memo[i] = solve(i-1) + solve(i-2); }', 'https://leetcode.com/problems/climbing-stairs/'),
                                                         ('Dynamic Programming (Tabulation)', 'Building a table bottom-up to find optimal solutions to subproblems.', 'int[] dp = new int[n + 1]; dp[0] = 0; dp[1] = nums[0]; for(int i=2; i<=n; i++) dp[i] = Math.max(dp[i-1], dp[i-2] + nums[i-1]);', 'https://leetcode.com/problems/house-robber/'),
                                                         ('Priority Queue (Top K Elements)', 'Using a Min-Heap to maintain the Top K elements in a data stream in O(N log K) time.', 'PriorityQueue<Integer> pq = new PriorityQueue<>(); for(int val : nums) { pq.add(val); if(pq.size() > k) pq.poll(); } return pq.peek();', 'https://leetcode.com/problems/kth-largest-element-in-an-array/'),
                                                         ('Graph (Union-Find)', 'Used to detect cycles in an undirected graph or group connected components efficiently.', 'int find(int i) { if(parent[i] == i) return i; return parent[i] = find(parent[i]); } void union(int i, int j) { parent[find(i)] = find(j); }', 'https://leetcode.com/problems/number-of-provinces/'),
                                                         ('Trie (Prefix Search)', 'Efficiently storing and retrieving strings based on character prefixes.', 'class TrieNode { TrieNode[] children = new TrieNode[26]; boolean isEnd; } void insert(String word) { TrieNode node = root; for(char c : word.toCharArray()) { if(node.children[c-''a''] == null) node.children[c-''a''] = new TrieNode(); node = node.children[c-''a'']; } node.isEnd = true; }', 'https://leetcode.com/problems/implement-trie-prefix-tree/'),
                                                         ('Graph (Dijkstra)', 'Greedy approach using a Priority Queue to find the shortest path in a weighted graph.', 'PriorityQueue<int[]> pq = new PriorityQueue<>((a,b) -> a[1] - b[1]); pq.add(new int[]{start, 0}); while(!pq.isEmpty()) { int[] curr = pq.poll(); int u = curr[0], dist = curr[1]; }', 'https://leetcode.com/problems/network-delay-time/'),
                                                         ('Greedy (Interval Scheduling)', 'Solving by making the best local choice, commonly by sorting intervals by their end times.', 'Arrays.sort(intervals, (a,b) -> Integer.compare(a[1], b[1])); int end = intervals[0][1], count = 1; for(int i=1; i<n; i++) { if(intervals[i][0] >= end) { count++; end = intervals[i][1]; } }', 'https://leetcode.com/problems/non-overlapping-intervals/'),
                                                         ('Bit Manipulation (XOR Trick)', 'XORing a number with itself cancels it out (a^a=0); great for finding missing or unique elements.', 'int res = 0; for(int num : nums) res ^= num; return res;', 'https://leetcode.com/problems/single-number/'),
                                                         ('Divide and Conquer (Merge Sort)', 'Splitting problems into halves and merging sorted results; useful for inversion counting.', 'void mergeSort(int[] arr, int l, int r) { if(l >= r) return; int mid = l + (r-l)/2; mergeSort(arr, l, mid); mergeSort(arr, mid+1, r); merge(arr, l, mid, r); }', 'https://leetcode.com/problems/reverse-pairs/'),
                                                         ('Topological Sort (Kahn''s)', 'Ordering tasks based on dependencies using in-degrees and a queue.', 'Queue<Integer> q = new LinkedList<>(); for(int i=0; i<n; i++) if(inDegree[i] == 0) q.add(i); while(!q.isEmpty()) { int curr = q.poll(); for(int neighbor : adj.get(curr)) if(--inDegree[neighbor] == 0) q.add(neighbor); }', 'https://leetcode.com/problems/course-schedule/'),
                                                         ('Monotonic Queue', 'Maintains a decreasing sequence in a Deque; used for sliding window maximums.', 'Deque<Integer> dq = new LinkedList<>(); for(int i=0; i<n; i++) { while(!dq.isEmpty() && dq.peekFirst() < i - k + 1) dq.pollFirst(); while(!dq.isEmpty() && nums[dq.peekLast()] < nums[i]) dq.pollLast(); dq.offerLast(i); }', 'https://leetcode.com/problems/sliding-window-maximum/'),
                                                         ('Kadane''s Algorithm', 'Finding maximum sum subarray in linear time; local max vs global max.', 'int currentSum = nums[0], maxSum = nums[0]; for(int i=1; i<n; i++) { currentSum = Math.max(nums[i], currentSum + nums[i]); maxSum = Math.max(maxSum, currentSum); }', 'https://leetcode.com/problems/maximum-subarray/'),
                                                         ('Binary Tree (In-order)', 'Left-Root-Right traversal; in a BST, this results in a sorted sequence.', 'void inorder(TreeNode root) { if(root == null) return; inorder(root.left); res.add(root.val); inorder(root.right); }', 'https://leetcode.com/problems/validate-binary-search-tree/'),
                                                         ('Graph (Flood Fill)', 'Applying DFS/BFS to update connected components in a 2D matrix.', 'void dfs(int[][] image, int r, int c, int color, int newColor) { if(r<0 || c<0 || r>=m || c>=n || image[r][c] != color) return; image[r][c] = newColor; dfs(image, r+1, c, color, newColor); ... }', 'https://leetcode.com/problems/flood-fill/'),
                                                         ('Binary Indexed Tree (Fenwick)', 'Provides efficient O(log n) prefix sum updates and point queries.', 'void update(int i, int delta) { while(i <= n) { bit[i] += delta; i += i & (-i); } } int query(int i) { int sum = 0; while(i > 0) { sum += bit[i]; i -= i & (-i); } return sum; }', 'https://leetcode.com/problems/range-sum-query-mutable/'),
                                                         ('Dutch National Flag', 'Sorts an array of 0s, 1s, and 2s in O(N) time with O(1) space using three pointers.', 'int low=0, mid=0, high=n-1; while(mid<=high){ if(arr[mid]==0) swap(low++, mid++); else if(arr[mid]==1) mid++; else swap(mid, high--); }', 'https://leetcode.com/problems/sort-colors/'),
                                                         ('Moore''s Voting Algorithm', 'Finds the majority element (appears > N/2 times) in O(N) time and O(1) space.', 'int count=0, candidate=0; for(int num : nums){ if(count==0) candidate=num; count += (num==candidate) ? 1 : -1; }', 'https://leetcode.com/problems/majority-element/'),
                                                         ('Linked List (Reverse)', 'Iteratively reversing a linked list by manipulating pointers.', 'ListNode prev=null, curr=head; while(curr!=null){ ListNode nextTemp=curr.next; curr.next=prev; prev=curr; curr=nextTemp; } return prev;', 'https://leetcode.com/problems/reverse-linked-list/'),
                                                         ('Linked List (Merge Two Sorted)', 'Merging two sorted lists using a dummy node to simplify edge cases.', 'ListNode dummy = new ListNode(0), tail = dummy; while(l1!=null && l2!=null){ if(l1.val < l2.val){ tail.next=l1; l1=l1.next; }else{ tail.next=l2; l2=l2.next; } tail=tail.next; } tail.next = (l1!=null) ? l1 : l2;', 'https://leetcode.com/problems/merge-two-sorted-lists/'),
                                                         ('LRU Cache', 'Combining a HashMap and Doubly Linked List to achieve O(1) get and put operations.', 'class Node { int key, val; Node prev, next; } Map<Integer, Node> map; void moveToHead(Node node){ removeNode(node); addNode(node); }', 'https://leetcode.com/problems/lru-cache/'),
                                                         ('Valid Parentheses', 'Using a stack to ensure brackets are closed in the correct order.', 'Stack<Character> st = new Stack<>(); for(char c : s.toCharArray()){ if(c==''('') st.push('')''); else if(c==''{'' ) st.push('''}'); else if(c==''['') st.push('']''); else if(st.isEmpty() || st.pop()!=c) return false; }', 'https://leetcode.com/problems/valid-parentheses/'),
                                                         ('Binary Tree (Pre-order)', 'Root-Left-Right traversal; useful for creating a copy of the tree.', 'void preorder(TreeNode root){ if(root==null) return; res.add(root.val); preorder(root.left); preorder(root.right); }', 'https://leetcode.com/problems/binary-tree-preorder-traversal/'),
                                                         ('Binary Tree (Post-order)', 'Left-Right-Root traversal; useful for deleting a tree or evaluating post-fix expressions.', 'void postorder(TreeNode root){ if(root==null) return; postorder(root.left); postorder(root.right); res.add(root.val); }', 'https://leetcode.com/problems/binary-tree-postorder-traversal/'),
                                                         ('Lowest Common Ancestor', 'Finding the deepest shared parent in a binary tree.', 'TreeNode LCA(TreeNode root, TreeNode p, TreeNode q){ if(root==null || root==p || root==q) return root; TreeNode left = LCA(root.left, p, q); TreeNode right = LCA(root.right, p, q); return left==null ? right : right==null ? left : root; }', 'https://leetcode.com/problems/lowest-common-ancestor-of-a-binary-tree/'),
                                                         ('Heap (Merge K Sorted)', 'Using a Min-Heap to merge k sorted lists in O(N log K) time.', 'PriorityQueue<ListNode> pq = new PriorityQueue<>((a,b)->a.val-b.val); for(ListNode node: lists) if(node!=null) pq.add(node); while(!pq.isEmpty()){ ListNode curr = pq.poll(); tail.next = curr; if(curr.next!=null) pq.add(curr.next); }', 'https://leetcode.com/problems/merge-k-sorted-lists/'),
                                                         ('Heap (Median of Stream)', 'Using two heaps (Max Heap for lower half, Min Heap for upper half) to find medians dynamically.', 'PriorityQueue<Integer> maxHeap = new PriorityQueue<>(Collections.reverseOrder()); PriorityQueue<Integer> minHeap = new PriorityQueue<>(); void addNum(int num){ maxHeap.offer(num); minHeap.offer(maxHeap.poll()); if(maxHeap.size() < minHeap.size()) maxHeap.offer(minHeap.poll()); }', 'https://leetcode.com/problems/find-median-from-data-stream/'),
                                                         ('Graph (Cycle Detection DFS)', 'Using node coloring (0=unvisited, 1=visiting, 2=visited) to detect back-edges.', 'boolean hasCycle(int u){ visited[u]=1; for(int v : adj.get(u)){ if(visited[v]==1) return true; if(visited[v]==0 && hasCycle(v)) return true; } visited[u]=2; return false; }', 'https://leetcode.com/problems/course-schedule/'),
                                                         ('Minimum Spanning Tree (Kruskal)', 'Sorting all edges and picking the smallest non-cycle creating edges using Union-Find.', 'Arrays.sort(edges, (a,b)->a[2]-b[2]); int cost=0, edgesUsed=0; for(int[] e : edges){ if(find(e[0]) != find(e[1])){ union(e[0], e[1]); cost+=e[2]; edgesUsed++; } }', 'https://leetcode.com/problems/min-cost-to-connect-all-points/'),
                                                         ('Bipartite Graph (BFS)', 'Checking if a graph can be colored with 2 colors without adjacent same-color nodes.', 'int[] colors = new int[n]; Arrays.fill(colors, -1); colors[start]=0; Queue<Integer> q = new LinkedList<>(); q.add(start); while(!q.isEmpty()){ int u = q.poll(); for(int v : adj[u]){ if(colors[v]==-1){ colors[v] = 1-colors[u]; q.add(v); } else if(colors[v]==colors[u]) return false; } }', 'https://leetcode.com/problems/is-graph-bipartite/'),
                                                         ('DP (2D Grid Paths)', 'Finding number of paths from top-left to bottom-right dynamically.', 'int[][] dp = new int[m][n]; for(int i=0; i<m; i++) dp[i][0] = 1; for(int j=0; j<n; j++) dp[0][j] = 1; for(int i=1; i<m; i++) for(int j=1; j<n; j++) dp[i][j] = dp[i-1][j] + dp[i][j-1];', 'https://leetcode.com/problems/unique-paths/'),
                                                         ('DP (0/1 Knapsack)', 'Finding max value for a given capacity where items can be picked once.', 'int[][] dp = new int[n+1][W+1]; for(int i=1; i<=n; i++){ for(int w=1; w<=W; w++){ if(wt[i-1] <= w) dp[i][w] = Math.max(val[i-1] + dp[i-1][w-wt[i-1]], dp[i-1][w]); else dp[i][w] = dp[i-1][w]; } }', 'https://leetcode.com/problems/partition-equal-subset-sum/'),
                                                         ('DP (Longest Common Subsequence)', 'Finding the longest sequence present in both strings in the same order.', 'int[][] dp = new int[m+1][n+1]; for(int i=1; i<=m; i++) for(int j=1; j<=n; j++){ if(s1.charAt(i-1) == s2.charAt(j-1)) dp[i][j] = 1 + dp[i-1][j-1]; else dp[i][j] = Math.max(dp[i-1][j], dp[i][j-1]); }', 'https://leetcode.com/problems/longest-common-subsequence/'),
                                                         ('DP (Longest Increasing Subsequence)', 'Finding the longest strictly increasing subsequence in an array.', 'int[] dp = new int[n]; Arrays.fill(dp, 1); int max = 1; for(int i=1; i<n; i++) for(int j=0; j<i; j++) if(nums[i] > nums[j]){ dp[i] = Math.max(dp[i], dp[j]+1); max = Math.max(max, dp[i]); }', 'https://leetcode.com/problems/longest-increasing-subsequence/'),
                                                         ('DP (Palindromic Substrings)', 'Expanding from centers to count or find palindromes efficiently.', 'int count = 0; for(int i=0; i<s.length(); i++){ count += extend(s, i, i); count += extend(s, i, i+1); } int extend(String s, int l, int r){ int res=0; while(l>=0 && r<s.length() && s.charAt(l)==s.charAt(r)){ res++; l--; r++; } return res; }', 'https://leetcode.com/problems/palindromic-substrings/'),
                                                         ('Backtracking (Subsets)', 'Generating all possible subsets (the power set) of an array.', 'void backtrack(int start, List<Integer> temp){ res.add(new ArrayList<>(temp)); for(int i=start; i<nums.length; i++){ temp.add(nums[i]); backtrack(i+1, temp); temp.remove(temp.size()-1); } }', 'https://leetcode.com/problems/subsets/'),
                                                         ('Backtracking (N-Queens)', 'Placing N queens on an NxN chessboard so no two attack each other.', 'boolean isValid(int row, int col){ for(int i=0; i<row; i++) if(board[i][col] == ''Q'') return false; // Add diagonal checks... return true; }', 'https://leetcode.com/problems/n-queens/'),
                                                         ('Bit Manipulation (Count Set Bits)', 'Brian Kernighan’s Algorithm to count 1s in a binary representation.', 'int count = 0; while(n > 0){ n = n & (n-1); count++; } return count;', 'https://leetcode.com/problems/number-of-1-bits/'),
                                                         ('Divide and Conquer (Quick Select)', 'Finding the Kth smallest/largest element in O(N) average time.', 'int partition(int[] arr, int l, int r){ int pivot=arr[r], i=l; for(int j=l; j<r; j++) if(arr[j] <= pivot) swap(arr, i++, j); swap(arr, i, r); return i; }', 'https://leetcode.com/problems/kth-largest-element-in-an-array/'),
                                                         ('Segment Tree (Build)', 'Advanced tree structure for fast range queries and updates.', 'void build(int node, int start, int end){ if(start==end){ tree[node]=arr[start]; return; } int mid = (start+end)/2; build(2*node, start, mid); build(2*node+1, mid+1, end); tree[node] = tree[2*node] + tree[2*node+1]; }', 'https://leetcode.com/problems/range-sum-query-mutable/'),
                                                         ('String Matching (KMP)', 'Using an LPS (Longest Prefix Suffix) array to find substrings in O(N) time.', 'int[] lps = computeLPS(pattern); int i=0, j=0; while(i < text.length()){ if(pattern.charAt(j) == text.charAt(i)){ i++; j++; } if(j == pattern.length()) return i-j; else if(i<text.length() && pattern.charAt(j)!=text.charAt(i)) { if(j!=0) j = lps[j-1]; else i++; } }', 'https://leetcode.com/problems/find-the-index-of-the-first-occurrence-in-a-string/'),
                                                         ('Two Pointers (Container With Most Water)', 'Maximizing area by moving the pointer pointing to the shorter line.', 'int maxArea=0, l=0, r=height.length-1; while(l<r){ maxArea = Math.max(maxArea, Math.min(height[l], height[r]) * (r-l)); if(height[l] < height[r]) l++; else r--; }', 'https://leetcode.com/problems/container-with-most-water/'),
                                                         ('Math (Sieve of Eratosthenes)', 'Generating all prime numbers up to N efficiently.', 'boolean[] isPrime = new boolean[n+1]; Arrays.fill(isPrime, true); isPrime[0]=false; isPrime[1]=false; for(int p=2; p*p<=n; p++){ if(isPrime[p]){ for(int i=p*p; i<=n; i+=p) isPrime[i] = false; } }', 'https://leetcode.com/problems/count-primes/');